        g: '03051000', avg: 410, histFlow: 375, mx: 395, my: 160, abbr: 'WV',
        desc: "Shavers Fork is a high-elevation tributary of the Tygart Valley River flowing through the Monongahela National Forest at elevations up to 3,500 feet. The upper river is one of West Virginia's most important native brook trout streams, while the middle reaches offer Class II–III whitewater paddling. The river parallels the Durbin & Greenbrier Valley scenic railroad through the Cheat Mountain backcountry.",
        desig: 'Monongahela National Forest · WV Native Brook Trout Stream',
        secs: ['Upper Shavers Fork — Cheat Bridge to Bemis, Class II, brook trout headwaters', 'Middle Shavers Fork — Bemis to Parsons, Class II–III, whitewater reach', 'High Falls of Cheat — dramatic waterfall near Glady, hike-in highlight'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Cheat Mountain Hunting Grounds', text: "The high ridges of Cheat Mountain and the Shavers Fork drainage were remote seasonal hunting grounds shared by Cherokee, Shawnee, and Seneca peoples. The dense red spruce forests at elevation — now largely cut over but recovering — held elk, bison, and cougar well into the 18th century.", src: 'Monongahela National Forest; WV Division of Culture and History' }] },
          { era: 'modern', entries: [{ yr: '2002', title: 'Shavers Fork Brook Trout Recovery', text: "The Mononghela National Forest and Trout Unlimited began a multi-year project to restore native brook trout habitat along Shavers Fork, addressing historic logging damage, acid deposition, and in-stream habitat. Brook trout numbers have rebounded significantly and the river remains a core refuge for wild native char in West Virginia.", src: 'USFS Monongahela NF; Trout Unlimited' }] },
        ],
        docs: [],
        revs: [],
        outs: [{ n: 'Elk River Touring Center', d: 'Shavers Fork and Monongahela NF trip planning', l: '' }],
