        co: 'Webster Co.', len: '33 mi', cls: 'II–III', opt: '100–500',
        g: '03186500', avg: 200, histFlow: 185, mx: 385, my: 175, abbr: 'WV',
        desc: "The Williams River is a small, remote mountain river in the heart of the Monongahela National Forest, flowing past the Cranberry Wilderness and through some of the finest native brook trout water in the eastern U.S. When it runs, the river offers tight technical Class II–III paddling through a deep hemlock canyon. Scenic Highway 150 follows the river for easy access.",
        desig: 'Monongahela National Forest · WV Native Brook Trout Stream · Highland Scenic Highway',
        secs: ['Tea Creek to Three Forks — Class II, upper river, brook trout', 'Three Forks to Dyer — Class II–III, gorge section', 'Dyer to Gauley confluence — Class II, lower reach'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Cranberry Backcountry Hunting Grounds', text: "The high country around the Williams and Cranberry rivers was shared seasonal hunting territory for Cherokee, Shawnee, and Seneca peoples. The cranberry bogs and spruce forests of this high plateau — now the Cranberry Wilderness — produced abundant game and medicinal plants unique to the southern Appalachian highlands.", src: 'Monongahela National Forest; WV Division of Culture and History' }] },
          { era: 'modern', entries: [{ yr: '1983', title: 'Cranberry Wilderness Designation', text: "Congress designated the 35,864-acre Cranberry Wilderness in 1983, protecting the headwaters and main stem of the Williams River within one of the largest wilderness areas in the eastern U.S. The designation safeguards critical native brook trout habitat and some of the most remote country remaining in West Virginia.", src: 'USFS Monongahela NF; Wilderness Society' }] },
        ],
        docs: [],
        revs: [],
        outs: [{ n: 'Cranberry Wilderness Backcountry', d: 'USFS ranger district for Williams River info', l: '' }],
