        co: 'Pitkin Co.', len: '70 mi', cls: 'I–III', opt: '300–3000',
        g: '09085000', avg: 1100, histFlow: 950, mx: 358, my: 102, abbr: 'CO',
        desc: "The Roaring Fork drops from Independence Pass near Aspen to its confluence with the Colorado at Glenwood Springs. The river runs through one of Colorado\"s most scenic mountain valleys, offering Class I–III whitewater with the Elk Mountains as a backdrop. The Crystal River tributary adds volume and drama. Peak snowmelt in June creates excellent intermediate whitewater.",
        desig: 'White River National Forest · Colorado Gold Medal candidate',
        secs: ['Upper — Aspen to Basalt, Class I–II, mountain valley', 'Middle — Basalt to Carbondale, Class II, Crystal River confluence', 'Lower — Carbondale to Glenwood Springs, Class II–III, best whitewater'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Ute Homeland — Roaring Fork Valley', text: 'The Roaring Fork valley was core Ute territory, used as a summer hunting ground and travel corridor over Independence Pass. The valley\"s hot springs near present-day Glenwood Springs were a sacred gathering site. The Meeker Incident of 1879 led to forced Ute removal from the valley.', src: 'Colorado State Historical Society; Aspen Historical Society' }] },
          { era: 'modern', entries: [{ yr: '2015', title: 'Roaring Fork Conservancy — Watershed Restoration', text: 'The Roaring Fork Conservancy completed a decade-long watershed restoration initiative, improving fish passage and streambank stability along 30 miles of river. The program has helped maintain the Roaring Fork as one of Colorado\"s healthiest mountain watersheds despite significant development pressure from Aspen.', src: 'Roaring Fork Conservancy; Colorado Parks and Wildlife' }] },
        ],
        docs: [],
        revs: [],
        needsVerification: ['cfs-range-wide'],
        outs: [{ n: 'Blazing Adventures', d: 'Roaring Fork and Colorado River rafting from Aspen', l: '' }],
