        secs: ['Yellowstone Park — Madison Junction to West Yellowstone, Class I, wildlife-rich', 'Quake Lake to Ennis — 50 mi, the 50-mile riffle, Class I–II, legendary trout water', 'Beartrap Canyon — Class IV–V, expert whitewater gorge below Ennis Lake', 'Lower Madison — Three Forks approach, Class I'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Crow and Shoshone Territory — Yellowstone Headwaters", text: "The Madison River valley was shared territory of the Crow (Apsaalooke), Shoshone, and Bannock peoples. The Yellowstone Plateau where the Madison originates was considered sacred ground. Lewis and Clark named the river for Secretary of State James Madison in 1805.", src: 'Yellowstone National Park; Montana Historical Society' }] },
          { era: 'modern', entries: [{ yr: '1959', title: "Hebgen Lake Earthquake — Quake Lake Created", text: "The 1959 Hebgen Lake earthquake (magnitude 7.3) triggered a massive landslide that dammed the Madison River, creating Quake Lake and killing 28 people. The earthquake fundamentally altered the upper Madison's hydrology and created the tailwater conditions that produce today's extraordinary trout fishery.", src: 'USGS; Earthquake Lake Visitor Center; Montana Historical Society' }] },
        ],
        docs: [{ t: 'Madison River Recreation Management Plan', s: 'Montana FWP', y: 2021, tp: 'Recreation', pg: 95, url: '' }],
