        g: '11421000', avg: 1600, histFlow: 1450, mx: 170, my: 85, abbr: 'CA',
        desc: "One of the Sierra Nevada's most beautiful whitewater rivers — the Yuba carves through deep granite canyons with emerald pools, Class III–IV rapids, and some of the clearest water in California. The South Fork's swimming holes near Nevada City are legendary, drawing crowds on hot summer days to pristine granite-lined pools.",
        desig: 'South Yuba River State Park · BLM Wild & Scenic Study Area',
        secs: ['South Fork — Edwards Crossing to Purdon Crossing, 6 mi, Class III–IV', 'North Fork — Goodyears Bar to Downieville, 12 mi, Class IV', 'Middle Fork — Milton to confluence, 10 mi, Class III–IV, remote'],
        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: "Nisenan and Maidu Homeland — Gold Country Foothills", text: "The Yuba River watershed was home to the Nisenan and Mountain Maidu peoples, who utilized the river's abundant salmon runs and acorn groves for thousands of years. The catastrophic Gold Rush beginning in 1848 brought hydraulic mining that buried miles of the Yuba under mining debris.", src: 'Nisenan Tribal Network; Malakoff Diggins State Historic Park' }] },
          { era: 'modern', entries: [{ yr: '2003', title: 'South Yuba River State Park and Trail Expansion', text: "South Yuba River State Park expanded trail access along the canyon rim, opening more of the river's legendary swimming holes and whitewater to the public. The 20-mile South Yuba Trail is now one of the most popular river hikes in the Sierra foothills.", src: 'California State Parks; South Yuba River Citizens League' }] },
        ],
        docs: [],
        revs: [],
        outs: [],
