        history: [
          { era: 'native', entries: [{ yr: 'Pre-contact', title: 'Karuk Homeland — Ishkêesh', text: "The Salmon River canyon was Karuk territory. The Karuk (which means 'upriver people') lived along the Klamath and Salmon rivers and centered their ceremonial life around salmon runs. The World Renewal ceremonies practiced each fall on the river are among the oldest continuously observed religious practices in North America.", src: 'Karuk Tribe; Klamath National Forest' }] },
          { era: 'modern', entries: [{ yr: '1981', title: 'Salmon River Wild & Scenic Designation', text: "Congress added the Salmon River to the National Wild & Scenic Rivers System in 1981, protecting the entire main stem and both forks through Klamath National Forest. The designation blocked proposed dams and preserved one of the last fully wild salmon and steelhead strongholds in California.", src: 'USFS Klamath National Forest; Salmon River Restoration Council' }] },
        ],
        docs: [],
        revs: [],
